#include <stdio.h>
#include <string.h>

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        char s[100005];
        scanf("%s", s);
        int n = strlen(s);
        int freq[26] = {0};
        for (int i = 0; i < n; i++) {
            freq[s[i] - 'a']++;
        }
        int oddCount = 0;
        for (int i = 0; i < 26; i++) {
            if (freq[i] % 2 != 0) {
                oddCount++;
            }
        }
        if (oddCount > 1) {
            printf("-1\n");
        } else {
            int mid = -1;
            for (int i = 0; i < 26; i++) {
                if (freq[i] % 2 != 0) {
                    mid = i;
                    break;
                }
            }
            int j = 0;
            for (int i = 0; i < 26; i++) {
                if (i != mid) {
                    for (int k = 0; k < freq[i] / 2; k++) {
                        printf("%d ", j + 1);
                        j++;
                    }
                }
            }
            if (mid != -1) {
                printf("%d ", j + 1);
                j++;
            }
            for (int i = 25; i >= 0; i--) {
                if (i != mid) {
                    for (int k = 0; k < freq[i] / 2; k++) {
                        printf("%d ", j + 1);
                        j++;
                    }
                }
            }
            printf("\n");
        }
    }
    return 0;
}

